var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>여성 생존자는 구조에 성공했습니다!</color>","JPN":"<color=#ffd34c>女性生存者の救助に成功しました！</color>","ENG":"<color=#ffd34c>We've secured the female survivor!</color>","TWN":"<color=#ffd34c>成功救出女性倖存者！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>수배자 확보! 건물 내부로 진입하겠습니다!</color>","JPN":"<color=#ffd34c>指名手配犯確保！　建物内部に進入します！</color>","ENG":"<color=#ffd34c>Felon located! We will now proceed into the building!</color>","TWN":"<color=#ffd34c>確認通緝犯！進入建築物內部！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>뭐, 뭐야……? 이건 완전 이면세계잖아……?</color>","JPN":"<color=#ffd34c>な、何だ……？　ここは、完全に裏世界じゃないか……？</color>","ENG":"<color=#ffd34c>H-huh…? Isn't this… the Counterside?</color>","TWN":"<color=#ffd34c>這……？這根本是異界吧……？</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음……. 건물 청소하려면 시간 깨나 걸리겠네.","JPN":"うーん……建物の掃除にだいぶ時間がかかりそうだわ。","ENG":"Hmm... Looks like it'll take a while to clean up this mess.","TWN":"嗯……看來整理會花上一些時間。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 뭐, 결과적으로는 서로한테 좋은 결과라고 해야 할까?","JPN":"でもまあ、最終的にはお互いに良い結果だったかしら。","ENG":"Then again, I guess this was a mutually agreeable solution?","TWN":"不過就結果而言，應該算是對雙方都好吧？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리는 어쨌든 멘탈 프린팅 기술의 초안은 확보했고…….","JPN":"とりあえず私たちはメンタル・プリンティング技術の草案を確保したし……","ENG":"One way or the other, we've managed to secure an early working version of the Mental Printing technology…","TWN":"反正我們有拿到智力複印技術的初版……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관리국은 전세계에 <color=#ffd34c>안주할 때가 아니다</color> 라고 메시지를 보낼 수 있었잖아.","JPN":"管理局は全世界に<color=#ffd34c>安住している場合じゃない</color>とメッセージを送れたし。","ENG":"And the Administration was able to send a message to the world saying \\"<color=#ffd34c>we mustn't grow complacent yet</color>\\".","TWN":"管理局也可以對全世界發出訊息，表示<color=#ffd34c>現在不是安逸的時刻</color>。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"1종이나 2종 같은 조무래기만 잡으면서 시시덕거리던 인간들에게는 좋은 충격요법이 되지 않았을까?","JPN":"第1種や第2種みたいな雑魚ばかり狩っていい気になっていた人間には良いショック療法になったんじゃない？","ENG":"It'll be a good shock to humans who were getting giddy about beating up small fry like Categories 1 or 2.","TWN":"這樣對那些抓到1類，或2類的小咖也在大驚小怪的人類，應該也是很棒的提醒吧？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"안 그래, 전대장님?","JPN":"そうでしょう、戦隊長さん？","ENG":"Wouldn't you agree, Commander?","TWN":"你說是不是，戰隊長？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……오랜만이군, 셰나.","JPN":"……久しいな、シェナ。","ENG":"…Long time no see, Shena.","TWN":"……好久不見，世娜。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스에게 자료를 전해 받았을 때는, 너희가 남긴 연구를 우연히 구했다고만 생각했다.","JPN":"アレックスから資料を受け取った時は、君たちが残した研究を偶然手に入れたのだと思っていたが。","ENG":"When Alex handed me the data, I thought she had stumbled on upon the research you left behind by chance.","TWN":"雅蕾克絲把資料給我時，我以為只是湊巧找到你們留下的研究。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"알렉스? 아, 그 불량품 A 타입?","JPN":"アレックス？　ああ、あの不良品のAのこと？","ENG":"Alex? Oh, you mean the Defect Type A?","TWN":"雅蕾克絲？喔～那個A型瑕疵品喔？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"물론 그 날 타격이 크긴 했어.","JPN":"まあ、あの日はかなりのダメージを受けたわね。","ENG":"True, we did take quite a hit that day.","TWN":"那天打擊應該很大吧。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"조직이 무너져서 남의 집에 얹혀 사는 데다, 지휘자님은 여전히 부재 중이시니까.","JPN":"組織は崩壊して他人の家に居候している上に、指揮者様は相変わらず不在だもの。","ENG":"With our organization dismantled, we've been reduced to mooching off someone else... and the Chief Conductor's still missing.","TWN":"組織瓦解後寄人籬下，因為指揮還是不在。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 우리는, <color=#ffd34c>엘리시움 필하모닉</color>은 죽지 않아. 여기 있는 나는 거울에 비친 상에 불과하니까.","JPN":"でもね、我々<color=#ffd34c>エリシウムフィルハーモニー</color>は死なないわ。ここにいる私は鏡に映った像に過ぎないから。","ENG":"But we of the <color=#ffd34c>Elysium Philharmonic</color> will not perish. What you see here is merely a mirror image of me.","TWN":"但我們<color=#ffd34c>愛樂組織</color>沒有瓦解，因為在這裡的我，不過是鏡子的倒影。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너희는…… 언제까지 그 성공할 수 없는 기술에 매달릴 셈이냐?","JPN":"君たちは……いつまでその成功の見込みもない技術にこだわるつもりだ？","ENG":"How long will you lot rely on that technology? Don't you know it'll never succeed?","TWN":"你們……到底要執著於那個不會成功的技術，到什麼時候？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리한테 뭐라고 하기 전에 자기부터 되돌아보시지 그래?","JPN":"私たちに説教する前に、まず自分のことを振り返ってみたらどうかしら？","ENG":"Why don't you reflect back on yourself before you lecture us?","TWN":"在說我們之前，要不要先看看你自己？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 꼴로 관리국의 개 노릇을 언제까지 할 수 있을 것 같아? 쓸모가 없어지는 그 즉시 버려질걸?","JPN":"そんな格好でいつまで管理局の犬でいられると思う？　使い道がなくなった途端捨てられるわよ？","ENG":"How long do you think you can play the Administration's dog in that state? They'll discard you the moment you're no longer of use to them.","TWN":"你以為你可以當管理局的走狗多久？等你沒有利用價值後，就會被一腳踢開的！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내 상관은 그럴 분이 아니다. 언행에 주의하도록, 그림자.","JPN":"私の上官はそんな方ではない。言葉に気を付けろ、シャドウ。","ENG":"My superior would do no such thing. Choose your words carefully, Shadow.","TWN":"我的長官不是這種人，請注意你的言行，暗影。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 뭐, 버려진 다음에 와도 늦지 않아. 우리한테는 짧은 순간일 테니까.","JPN":"フフッ。まあ、捨てられた後に来ても遅くないわ。私たちにとってはわずかな時間にすぎないし。","ENG":"Heh. Well, it's not too late to come to us after you've been discarded. To us, the wait will feel no longer than a blinking moment.","TWN":"呵呵，等你被踢開後再來也不遲，反正是早晚的事！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"쉽게 보내 줄 거라고 생각하나?","JPN":"大人しく見逃してやると思ってるのか？","ENG":"Do you think I'd let you go so easily?","TWN":"你以為我會這麼輕易就放你走嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어차피 너, 주인 명령 없이는 제대로 싸우지도 못하잖아?","JPN":"どうせあなたは主の命令なしではまともに戦えないでしょ？","ENG":"Well, you can't even fight properly without your master's orders, right?","TWN":"反正沒有主人的命令，你動都不敢動不是嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 주인한테 가서 전해. 마왕이니 클리포트 게임이니 거창한 이야기도 중요하겠지만…….","JPN":"あなたの主のところに帰ったら伝えて。魔王だのクリフォトゲームだの大げさな話も大事だけど……","ENG":"Just go tell your master. All that fancy talk about Demon Lords and Qliphoth Game aside…","TWN":"去告訴你的主人，不管是魔王，還是逆卡巴拉遊戲，這些雖然也很重要……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"인간들은 당신 생각보다 자멸하고 싶어서 애가 타는 것들이라고.","JPN":"人間たちはあなたが思うより自滅したくて仕方がない存在だと。","ENG":"Humans are more desperate to destroy themselves than you'd think.","TWN":"人類可是比你想像中還要更努力要自取滅亡。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……학회에 대한 이야기인가?","JPN":"……学会のことか？","ENG":"…You mean the Society?","TWN":"……你是在說學會嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄? 궁금하면 직접 알아 보는 게 어때?","JPN":"さあね？　気になるなら直接調べてみたら？","ENG":"Who knows? Why don't you find out for yourself if you're really so curious?","TWN":"誰知道？想知道不會自己去查嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아, 혹시 생각이 바뀌면 언제라도 우릴 찾아 와.","JPN":"あ、もし気が変わったらいつでも私たちのところに来てね。","ENG":"You're always welcome to seek us out if you ever change your mind.","TWN":"還有，要是你改變心意的話，隨時來找我們。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너라면 동료들도 매몰차게 쫓아내진 않을 테니까.","JPN":"あなたなら仲間たちも冷たく追い払うことはしないと思うわ。","ENG":"I'm sure with you, my colleagues won't drive you away so heartlessly.","TWN":"你的話，同事們應該不會趕你走啦。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"괜찮으십니까, 전대장님.","JPN":"大丈夫ですか、戦隊長殿。","ENG":"Are you alright, ma'am?","TWN":"戰隊長，你還好嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"여전하더군. 알렉스를 대기시키고 오길 잘했어.","JPN":"相変わらずだったよ。アレックスを待機させておいて正解だった。","ENG":"She hasn't changed a bit. It's a good thing I left Alex on standby.","TWN":"我沒事，讓雅蕾克絲待命果然是對的。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But…","TWN":"不過……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"걱정되십니까? 아까 차원 균열을 틀어막았던 그것 때문에?","JPN":"心配ですか？　さっき次元の亀裂を塞いだアレのせいで？","ENG":"Are you worried? Is it because of that thing that plugged the dimensional rift earlier?","TWN":"不放心嗎？是因為剛才次大峽谷堵住的關係嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래. 시무르그였다.","JPN":"ああ、シムルグだった。","ENG":"Yes. It was Simurgh.","TWN":"沒錯，是西摩格。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"네. 그 창백한 청백광……. 어제 일처럼 생생하게 기억하고 있습니다.","JPN":"はい。あの青白い光……昨日のことのように、はっきりと覚えています。","ENG":"Right. That pale bluish light… I remember it vividly as if it was yesterday.","TWN":"是，那個白淨的光……現在想起來還歷歷在目呢。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"요격이 성공했다고 해서 완전히 파괴된 줄 알았는데, 프레임은 건재했나 보군요.","JPN":"迎撃に成功したと聞いたので完全に破壊されたと思っていましたが、フレームは健在だったようですね。","ENG":"I thought it was completely destroyed with the successful intercept, but it seems the frame remained intact.","TWN":"因為說狙擊成功，還以為已經斬草除根，沒想到軀殼還在。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"괜찮을까요, 전대장님?","JPN":"大丈夫でしょうか、戦隊長殿？","ENG":"Are you sure about this, ma'am?","TWN":"戰隊長，這樣沒問題嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"당시에는 단순히 모더레이터처럼 정보오염된 기갑병기로 알고 있었지만, 저건 <color=#ffd34c>사도</color>입니다.","JPN":"当時はモデレーターのような情報汚染された単なる機甲兵器だと認識していましたが、あれは<color=#ffd34c>使徒</color>です。","ENG":"At the time we thought it was just another armored system with data corruption like the Moderator, but that thing is an <color=#ffd34c>Apostle</color>.","TWN":"當初還以為像仲裁者一樣，只是單純受到情報污染的機甲兵器，原來那個是<color=#ffd34c>使徒</color>。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아니. 인공지능이 다르다면 적의 무기를 노획해서 사용하는 것과 다를 바 없다.","JPN":"いや、異なる人工知能なら、敵の武器を鹵獲して使用するのと変わらない。","ENG":"Wrong. With a different AI, this is no different than using weapons captured from an enemy.","TWN":"不，不同的人工智慧的話，就像把敵人的武器拿來用一樣。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"Besides…","TWN":"而且……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>녀석의 동력원은 파괴했어! 이면세계로 도주하기 전에 어떻게든 막아야 돼!</color>","JPN":"<color=#ffd34c>他の戦隊員は全滅状態だ！　現実世界に突入する前に何とか阻止しなければ！</color>","ENG":"<color=#ffd34c>Her power source is destroyed! We have to stop her before she retreats to the Counterside!</color>","TWN":"<color=#ffd34c>其他戰隊員全軍覆沒！回到現世前，無論如何都要擋住！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"지휘부다! 당장 복귀해, 전대장! 혼자 달려들어서 뭘 어떻게 하려고!","JPN":"指令部からの指示だ！　直ちに復帰しろ、戦隊長！　一人で飛び込んでどうするつもりだ！","ENG":"This is HQ Command! Return to base immediately, Commander! Rushing in there alone won't achieve anything!","TWN":"這裡是指揮部！立刻回來！戰隊長，你單槍匹馬衝進去是想幹嘛！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>차원 도약 직전에 궤도를 틀어 버리면 돼! 기동 전이라면 분명 타격을 가할 수 있어!</color>","JPN":"<color=#ffd34c>次元跳躍の直前に軌道を曲げさせればいい！　起動前ならきっとダメージを与えられる！</color>","ENG":"<color=#ffd34c>All we need to do is change the trajectory right before the dimension jump! I know that thing will take damage if I strike before it activates!</color>","TWN":"<color=#ffd34c>只需要在次元跳躍前扭轉軌跡就好！若是啟動前，一定可以攻擊到他！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"거기에 휘말린 자네는! 단거리 공간 도약으로는 벗어날 수 없어! 죽는다고!","JPN":"それに巻き込まれる君は一体どうなるんだ！　短距離空間跳躍では抜け出せない！　死ぬぞ！","ENG":"But what if you get caught up in it? You won't get away with just a short-distance space jump! You'll get yourself killed!","TWN":"但你被捲入後，可是無法靠短距離空間跳躍離開的！會死人的！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>한 걸음만, 1초만 더 빨랐으면 하는 후회는 이제 지긋지긋해!</color>","JPN":"<color=#ffd34c>あと一歩、あと1秒でも早かったならと後悔するのはもううんざりだ！</color>","ENG":"<color=#ffd34c>I've had enough of regretting that I was one step sooner or one second earlier!</color>","TWN":"<color=#ffd34c>要是你再早一步，或早一秒，現在就後悔莫及了！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이번에야말로…… 모두를 구하겠어!</color>","JPN":"<color=#ffd34c>だからここでは……手遅れになる前に救い出す！</color>","ENG":"<color=#ffd34c>So for once… I'll save everyone!</color>","TWN":"<color=#ffd34c>所以我要在這裡……趁早挽救！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……어쩌면 앨리스 전대장이 우리에게 남겨 준 것일지도 모르지.","JPN":"……もしかしたらアリス戦隊長が私たちに残してくれたものかもしれない。","ENG":"…Perhaps this was something Commander Alice left behind for us.","TWN":"……很可能是愛麗絲小隊長留給我們的東西。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"프리드웬 기관을 도와 학회를 견제한다는 작전 목표는 이미 달성했다.","JPN":"プリドウェン機関に協力し、学会を牽制するという作戦目標はすでに達成している。","ENG":"We've already accomplished our objective of aiding the Prydwen Institution to keep the Society in check.","TWN":"已達成幫助普利多溫機關牽制學會的作戰目標。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"메이즈 전대. 현장에서 철수한다.","JPN":"メイズ戦隊、現場から撤収する。","ENG":"Maze Division. It's time to withdraw from the AO.","TWN":"梅茲戰隊，從現場撤退。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};